import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"MCP API","description":"","frontmatter":{},"headers":[],"relativePath":"guide/mcp-api.md","filePath":"guide/mcp-api.md"}'),n={name:"guide/mcp-api.md"};function i(s,t,d,l,c,u){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="mcp-api" tabindex="-1">MCP API <a class="header-anchor" href="#mcp-api" aria-label="Permalink to &quot;MCP API&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The TeamCentral MCP (Model Context Protocol) API enables AI assistants — such as Claude, ChatGPT, and Microsoft Copilot — to interact directly with your TeamCentral data through a standardized protocol. Once connected, an AI assistant can query your data models, look up entities, execute saved queries, extract file content, and submit data entry forms on behalf of authenticated users.</p><p>The MCP API acts as a bridge between AI platforms and your existing TeamCentral Platform API, translating natural language interactions into structured API calls while enforcing the same authentication and authorization policies that govern your platform.</p><div class="info custom-block"><p class="custom-block-title">What is MCP?</p><p>The <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">Model Context Protocol</a> is an open standard that allows AI models to discover and use external tools and data sources. TeamCentral implements MCP so that AI assistants can securely access your integration data without custom per-platform development.</p></div><h2 id="connecting-to-teamcentral" tabindex="-1">Connecting to TeamCentral <a class="header-anchor" href="#connecting-to-teamcentral" aria-label="Permalink to &quot;Connecting to TeamCentral&quot;">​</a></h2><h3 id="claude" tabindex="-1">Claude <a class="header-anchor" href="#claude" aria-label="Permalink to &quot;Claude&quot;">​</a></h3><p>To connect Claude to your TeamCentral instance:</p><ol><li>Open <strong>Claude.ai</strong>, <strong>Claude Desktop</strong>, or <strong>Claude Code</strong></li><li>Navigate to the MCP server settings and add a new remote server</li><li>Enter your TeamCentral MCP API URL (provided by your administrator)</li><li>Complete the OAuth sign-in flow — you will be redirected to Microsoft Entra to authenticate with your organizational credentials</li><li>Grant consent for the MCP server to access TeamCentral on your behalf</li></ol><p>Once connected, Claude can use all available TeamCentral tools in your conversations.</p><h3 id="chatgpt" tabindex="-1">ChatGPT <a class="header-anchor" href="#chatgpt" aria-label="Permalink to &quot;ChatGPT&quot;">​</a></h3><p>To connect ChatGPT to your TeamCentral instance:</p><ol><li>Open <strong>ChatGPT</strong> and navigate to settings</li><li>Add a new MCP connection and enter your TeamCentral MCP API URL</li><li>Complete the OAuth sign-in flow through Microsoft Entra</li><li>Grant consent for the MCP server to access TeamCentral on your behalf</li></ol><h3 id="microsoft-copilot" tabindex="-1">Microsoft Copilot <a class="header-anchor" href="#microsoft-copilot" aria-label="Permalink to &quot;Microsoft Copilot&quot;">​</a></h3><p>For Microsoft Copilot integrations (Copilot Studio, M365 Copilot), contact your TeamCentral administrator. These platforms use a pre-configured connector and may require additional setup in your Entra tenant.</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>The MCP API uses <strong>OAuth 2.0</strong> with <strong>Microsoft Entra ID</strong> for authentication. When you connect an AI assistant to TeamCentral, the following occurs:</p><ol><li><strong>Authorization</strong> — You sign in with your Microsoft Entra credentials</li><li><strong>Consent</strong> — You approve the MCP server to access TeamCentral on your behalf. A single consent prompt provisions both the MCP API and Platform API in your tenant</li><li><strong>Token exchange</strong> — The MCP API exchanges your token for a Platform API token using the On-Behalf-Of (OBO) flow</li><li><strong>Scoped access</strong> — All data access is limited to what your user account has permission to see in TeamCentral</li></ol><div class="warning custom-block"><p class="custom-block-title">Important</p><p>The MCP API enforces the same permissions as the TeamCentral platform. Users can only access data models, entities, and saved queries that their account has been granted access to.</p></div><h2 id="available-tools" tabindex="-1">Available Tools <a class="header-anchor" href="#available-tools" aria-label="Permalink to &quot;Available Tools&quot;">​</a></h2><p>The following tools are available to AI assistants through the MCP API. Each tool summary is shown below — for complete input schemas, parameter details, and usage notes, see the <a href="./mcp-api-tool-reference.html">MCP Tool Reference</a>.</p><h3 id="data-models" tabindex="-1">Data Models <a class="header-anchor" href="#data-models" aria-label="Permalink to &quot;Data Models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th><th>Type</th></tr></thead><tbody><tr><td><code>get_data_models</code></td><td>Returns all Data Models configured in your environment</td><td>Read-only</td></tr><tr><td><code>get_data_model_properties</code></td><td>Returns the properties (fields) of a specific Data Model</td><td>Read-only</td></tr></tbody></table><p>These tools allow an AI assistant to understand the structure of your data — what models exist and what fields they contain — before querying or submitting data.</p><h3 id="entity-lookup-query" tabindex="-1">Entity Lookup &amp; Query <a class="header-anchor" href="#entity-lookup-query" aria-label="Permalink to &quot;Entity Lookup &amp; Query&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th><th>Type</th></tr></thead><tbody><tr><td><code>lookup_by_keyword</code></td><td>Searches for entities by keyword across related entity types</td><td>Read-only</td></tr><tr><td><code>query_entities</code></td><td>Queries entities with filters, sorting, pagination, and optional property selection</td><td>Read-only</td></tr><tr><td><code>get_entities_by_ids</code></td><td>Retrieves one or more entities by their unique IDs</td><td>Read-only</td></tr></tbody></table><h4 id="query-operators" tabindex="-1">Query Operators <a class="header-anchor" href="#query-operators" aria-label="Permalink to &quot;Query Operators&quot;">​</a></h4><p>When using <code>query_entities</code>, the following filter operators are available:</p><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>EqualTo</code></td><td>Exact match</td></tr><tr><td><code>NotEqualTo</code></td><td>Not equal</td></tr><tr><td><code>GreaterThan</code></td><td>Greater than</td></tr><tr><td><code>GreaterThanEqualTo</code></td><td>Greater than or equal</td></tr><tr><td><code>LessThan</code></td><td>Less than</td></tr><tr><td><code>LessThanEqualTo</code></td><td>Less than or equal</td></tr><tr><td><code>Contains</code></td><td>Contains substring</td></tr><tr><td><code>StartsWith</code></td><td>Starts with</td></tr><tr><td><code>NotStartsWith</code></td><td>Does not start with</td></tr><tr><td><code>EndsWith</code></td><td>Ends with</td></tr><tr><td><code>NotEndsWith</code></td><td>Does not end with</td></tr></tbody></table><h3 id="saved-queries" tabindex="-1">Saved Queries <a class="header-anchor" href="#saved-queries" aria-label="Permalink to &quot;Saved Queries&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th><th>Type</th></tr></thead><tbody><tr><td><code>get_saved_queries</code></td><td>Lists all Saved Queries (Live Data Providers) accessible to the user</td><td>Read-only</td></tr><tr><td><code>get_saved_query_details</code></td><td>Returns metadata and mapped fields for a Saved Query</td><td>Read-only</td></tr><tr><td><code>execute_saved_query</code></td><td>Executes a Saved Query with optional input parameters</td><td>Read-only</td></tr></tbody></table><p>Saved Queries allow administrators to define pre-built queries with parameters that AI assistants can execute. This is useful for common lookups like &quot;show me all open opportunities&quot; or &quot;find employees in a specific department.&quot;</p><h3 id="data-entry" tabindex="-1">Data Entry <a class="header-anchor" href="#data-entry" aria-label="Permalink to &quot;Data Entry&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th><th>Type</th></tr></thead><tbody><tr><td><code>get_data_entry_form</code></td><td>Retrieves a data entry form for a Data Model, optionally pre-populated</td><td>Read-only</td></tr><tr><td><code>submit_data_entry_form</code></td><td>Submits a completed data entry form to create or update a record</td><td><strong>Destructive</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The <code>get_data_entry_form</code> tool can return forms in JSON or Adaptive Card format. JSON format provides field metadata for conversational data entry, while Adaptive Cards render rich forms in platforms that support them (e.g. Microsoft Teams).</p></div><h3 id="file-extraction" tabindex="-1">File Extraction <a class="header-anchor" href="#file-extraction" aria-label="Permalink to &quot;File Extraction&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th><th>Type</th></tr></thead><tbody><tr><td><code>get_file_text</code></td><td>Extracts readable text from document URLs (PDF, DOCX, PPTX, HTML, and more)</td><td>Read-only</td></tr></tbody></table><p>When query results include File entities with an <code>externalFileLocation</code> property, use <code>get_file_text</code> to extract the document&#39;s text content. The tool returns text in chunks — call repeatedly using the <code>nextOffset</code> value until <code>hasMore</code> is <code>false</code>.</p><h2 id="example-interactions" tabindex="-1">Example Interactions <a class="header-anchor" href="#example-interactions" aria-label="Permalink to &quot;Example Interactions&quot;">​</a></h2><p>Here are examples of how an AI assistant might use these tools in a conversation:</p><p><strong>Exploring available data:</strong></p><blockquote><p>&quot;What data models are available in TeamCentral?&quot;</p><p>The assistant calls <code>get_data_models</code> and presents a list of your configured models.</p></blockquote><p><strong>Looking up a record:</strong></p><blockquote><p>&quot;Find me the customer record for Contoso&quot;</p><p>The assistant calls <code>lookup_by_keyword</code> with &quot;Contoso&quot; to find matching entities.</p></blockquote><p><strong>Running a report:</strong></p><blockquote><p>&quot;Show me all open purchase orders over $10,000&quot;</p><p>The assistant calls <code>get_saved_queries</code> to find a relevant query, then <code>execute_saved_query</code> with the appropriate parameters.</p></blockquote><p><strong>Submitting data:</strong></p><blockquote><p>&quot;Create a new support ticket for Contoso about a billing issue&quot;</p><p>The assistant calls <code>get_data_entry_form</code> to get the form structure, fills in the values from your request, and calls <code>submit_data_entry_form</code> to create the record.</p></blockquote><p><strong>Reading a document:</strong></p><blockquote><p>&quot;What does the attached contract say about payment terms?&quot;</p><p>The assistant retrieves the file entity, then calls <code>get_file_text</code> with the document URL to extract and analyze the text content.</p></blockquote><h2 id="administrator-setup" tabindex="-1">Administrator Setup <a class="header-anchor" href="#administrator-setup" aria-label="Permalink to &quot;Administrator Setup&quot;">​</a></h2><p>For administrators deploying the MCP API for their organization, the following setup is required:</p><ul><li>Entra app registration and configuration</li><li>Environment variables and deployment</li><li>Connector Security tab setup</li></ul><div class="warning custom-block"><p class="custom-block-title">Note</p><p>The MCP API requires three Entra app registrations (Connector, MCP API, and Central Platform API) and an Azure Storage account for OAuth state management. Once deployed, users can connect their AI assistant without additional admin setup — OAuth client registration is handled automatically. Contact your TeamCentral representative for detailed setup instructions.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h3><p><strong>&quot;Unauthorized&quot; or sign-in fails</strong></p><ul><li>Verify your Entra credentials are correct and your account has access to TeamCentral</li><li>Check that the MCP API&#39;s Entra app registration is properly configured</li><li>Ensure you have completed the consent prompt when first connecting</li></ul><p><strong>No data models or entities returned</strong></p><ul><li>Confirm your user account has the appropriate roles and permissions in TeamCentral</li><li>Verify that Data Models and Connectors are configured and active in your environment</li></ul><p><strong>Form submission fails</strong></p><ul><li>Check that all required fields are populated</li><li>Review the error message — the MCP API returns field-level validation errors when available</li></ul><p><strong>Connection timeout or slow responses</strong></p><ul><li>Large query results are automatically truncated to stay within platform limits</li><li>Use filters and the <code>properties</code> parameter to narrow results when querying large datasets</li><li>For paginated queries, use smaller <code>pageSize</code> values to reduce individual response size</li></ul>',64)])])}const m=e(n,[["render",i]]);export{p as __pageData,m as default};
